 115→function formatTime(time: string): string {
 116→  const parts = time.split(':').map(Number);
 117→  const hours = parts[0] ?? 0;
 118→  const minutes = parts[1] ?? 0;
 119→  const period = hours >= 12 ? 'PM' : 'AM';
 120→  const h = hours % 12 || 12;
 121→  return `${h}:${String(minutes).padStart(2, '0')} ${period}`;
 122→}
 123→
 124→function formatDueLabel(dueDate: Date, renderNow: Date): string {
 125→  const todayStart = new Date(renderNow);
 126→  todayStart.setHours(0, 0, 0, 0);
 127→  const dueStart = new Date(dueDate);
 128→  dueStart.setHours(0, 0, 0, 0);
 129→
 130→  const diffDays = Math.round(
 131→    (dueStart.getTime() - todayStart.getTime()) / (1000 * 60 * 60 * 24),
 132→  );
 133→
 134→  if (diffDays === 0) return 'Today';
 135→  if (diffDays === 1) return 'Tomorrow';
 136→  if (diffDays === -1) return 'Yesterday';
 137→  if (diffDays < 0) return `${Math.abs(diffDays)} days overdue`;
 138→  if (diffDays <= 7) return `In ${diffDays} days`;
 139→  return dueDate.toLocaleDateString(undefined, {
 140→    month: 'short',
 141→    day: 'numeric',
 142→  });
 143→}
 144→
 145→function repeatLabel(repeat: RepeatOption): string {
 146→  const found = REPEAT_OPTIONS.find(r => r.value === repeat);
 147→  return found?.label ?? 'None';
 148→}
 149→
 150→function isSameDay(a: Date, b: Date): boolean {
 151→  return (
 152→    a.getFullYear() === b.getFullYear() &&
 153→    a.getMonth() === b.getMonth() &&
 154→    a.getDate() === b.getDate()
 155→  );
 156→}
 157→
 158→function rowToEntry(row: ReminderRow): ReminderEntry {
 159→  const dueDate = new Date(row.due_date);
 160→  const completedAt = row.completed_at ? new Date(row.completed_at) : null;
 161→  const createdAt = new Date(row.created_at);
 162→  return {
 163→    id: row.id,
 164→    title: row.title,
 165→    dueDate: isNaN(dueDate.getTime()) ? new Date() : dueDate,
 166→    dueTime: row.due_time,
 167→    repeat: isRepeatOption(row.repeat) ? row.repeat : 'none',
 168→    notes: row.notes,
 169→    completed: row.completed === 1,
 170→    completedAt:
 171→      completedAt && !isNaN(completedAt.getTime()) ? completedAt : null,
 172→    createdAt: isNaN(createdAt.getTime()) ? new Date() : createdAt,
 173→  };
 174→}
 175→
 176→function entryToRow(entry: ReminderEntry): ReminderRow {
 177→  return {
 178→    id: entry.id,
 179→    title: entry.title,
 180→    due_date: entry.dueDate.toISOString(),
 181→    due_time: entry.dueTime,
 182→    repeat: entry.repeat,
 183→    notes: entry.notes,
 184→    completed: entry.completed ? 1 : 0,
 185→    completed_at: entry.completedAt?.toISOString() ?? null,
 186→    created_at: entry.createdAt.toISOString(),
 187→  };
 188→}
