 190→type ReminderSubView = 'list' | 'create' | 'edit';
 191→
 192→interface ReminderFormState {
 193→  title: string;
 194→  dueDate: string;
 195→  dueTime: string;
 196→  repeat: RepeatOption;
 197→  notes: string;
 198→}
 199→
 200→const INITIAL_FORM: ReminderFormState = {
 201→  title: '',
 202→  dueDate: new Date().toISOString().slice(0, 10),
 203→  dueTime: '09:00',
 204→  repeat: 'none',
 205→  notes: '',
 206→};
