 318→const FILTER_SECTIONS: SearchDropdownSection[] = [
 319→  {
 320→    options: [
 321→      {
 322→        label: 'All',
 323→        value: 'all',
 324→      },
 325→    ],
 326→  },
 327→  {
 328→    title: 'Status',
 329→    options: [
 330→      {
 331→        label: 'Active',
 332→        value: 'active',
 333→      },
 334→      {
 335→        label: 'Completed',
 336→        value: 'completed',
 337→      },
 338→    ],
 339→  },
