 342→export function RemindersView() {
 343→  const nav = useNavigation();
 344→  const [entries, setEntries] = useState<ReminderEntry[]>([]);
 345→  const [query, setQuery] = useState('');
 346→  const [filterValue, setFilterValue] = useState('all');
 347→  const [selectedIndex, setSelectedIndex] = useState(0);
 348→  const [actionsOpen, setActionsOpen] = useState(false);
 349→  const [subView, setSubView] = useState<ReminderSubView>('list');
 350→  const [editingReminder, setEditingReminder] = useState<
 351→    ReminderEntry | undefined
 352→  >();
 353→  const { items: hudItems, show: showHUD } = useHUD();
 354→  const { alertState, confirmAlert, dismiss: dismissAlert } = useAlert();
 355→
 356→  useEffect(() => {
 357→    let aborted = false;
 358→
 359→    reminderDb
 360→      .getAll()
 361→      .then(rows => {
 362→        if (aborted) return;
 363→        if (rows.length > 0) {
 364→          setEntries(rows.map(rowToEntry));
 365→        } else if (!isTauri) {
 366→          const mock = MOCK_REMINDER_ENTRIES.map(e => ({ ...e }));
 367→          setEntries(mock);
 368→          Promise.all(mock.map(e => reminderDb.insert(entryToRow(e)))).catch(
 369→            console.error,
 370→          );
 371→        }
 372→      })
 373→      .catch(err => {
 374→        console.error('Failed to load reminders:', err);
 375→        if (!isTauri && !aborted) {
 376→          setEntries(MOCK_REMINDER_ENTRIES.map(e => ({ ...e })));
 377→        }
 378→      });
 379→
 380→    return () => {
 381→      aborted = true;
 382→    };
 383→  }, []);
 384→
 385→  const dbSearchFn = useCallback((q: string) => reminderDb.search(q), []);
 386→  const { results: ftsResults, invalidate: invalidateFts } = useDbSearch(
 387→    query,
 388→    dbSearchFn,
 389→    rowToEntry,
 390→  );
 391→
 392→  const filtered = useMemo(() => {
 393→    let items = ftsResults ?? entries;
 394→
 395→    if (filterValue === 'active') {
 396→      items = items.filter(e => !e.completed);
 397→    } else if (filterValue === 'completed') {
 398→      items = items.filter(e => e.completed);
 399→    }
 400→
 401→    if (!ftsResults && query) {
 402→      items = items.filter(
 403→        e => fuzzyMatch(query, e.title) || fuzzyMatch(query, e.notes),
 404→      );
 405→    }
 406→
 407→    return items;
 408→  }, [
 409→    entries,
 410→    query,
 411→    filterValue,
 412→    ftsResults,
 413→  ]);
 414→
 415→  const renderNow = useMemo(() => new Date(), [filtered]);
 416→
 417→  const sections = useMemo(() => {
 418→    const todayStart = new Date(renderNow);
 419→    todayStart.setHours(0, 0, 0, 0);
 420→    const tomorrowStart = new Date(todayStart);
 421→    tomorrowStart.setDate(tomorrowStart.getDate() + 1);
 422→
 423→    const overdue: ReminderEntry[] = [];
 424→    const today: ReminderEntry[] = [];
 425→    const upcoming: ReminderEntry[] = [];
 426→    const completed: ReminderEntry[] = [];
 427→
 428→    for (const entry of filtered) {
 429→      if (entry.completed) {
 430→        completed.push(entry);
 431→        continue;
 432→      }
 433→      const dueStart = new Date(entry.dueDate);
 434→      dueStart.setHours(0, 0, 0, 0);
 435→
 436→      if (dueStart.getTime() < todayStart.getTime()) {
 437→        overdue.push(entry);
 438→      } else if (isSameDay(dueStart, todayStart)) {
 439→        today.push(entry);
 440→      } else {
 441→        upcoming.push(entry);
 442→      }
 443→    }
 444→
 445→    return {
 446→      overdue,
 447→      today,
 448→      upcoming,
 449→      completed,
 450→    };
 451→  }, [
 452→    filtered,
 453→    renderNow,
 454→  ]);
 455→
 456→  const totalItemCount = filtered.length;
 457→
 458→  useEffect(() => {
 459→    if (totalItemCount === 0) {
 460→      setSelectedIndex(0);
 461→    } else {
 462→      setSelectedIndex(prev =>
 463→        prev >= totalItemCount ? totalItemCount - 1 : prev);
 464→    }
 465→  }, [totalItemCount]);
 466→
 467→  const selectedEntry = filtered[selectedIndex];
 468→
 469→  const handleQueryChange = useCallback((value: string) => {
 470→    setQuery(value);
 471→    setSelectedIndex(0);
 472→    setActionsOpen(false);
 473→  }, []);
 474→
 475→  const handleFilterChange = useCallback((value: string) => {
 476→    setFilterValue(value);
 477→    setSelectedIndex(0);
 478→    setActionsOpen(false);
 479→  }, []);
 480→
 481→  const handleActiveIndexChange = useCallback((index: number) => {
 482→    setSelectedIndex(index);
 483→    setActionsOpen(false);
 484→  }, []);
 485→
 486→  const handleToggleComplete = useCallback(() => {
 487→    if (!selectedEntry) return;
 488→    const entryId = selectedEntry.id;
 489→    const wasCompleted = selectedEntry.completed;
 490→    const now = new Date();
 491→
 492→    setEntries(prev =>
 493→      prev.map(e =>
 494→        e.id === entryId
 495→          ? {
 496→              ...e,
 497→              completed: !wasCompleted,
 498→              completedAt: wasCompleted ? null : now,
 499→            }
 500→          : e));
 501→
 502→    reminderDb
 503→      .update(entryId, {
 504→        completed: wasCompleted ? 0 : 1,
 505→        completed_at: wasCompleted ? null : now.toISOString(),
 506→      })
 507→      .catch(console.error);
 508→
 509→    showHUD({
 510→      icon: wasCompleted ? <ClockIcon /> : <CheckIcon />,
 511→      title: wasCompleted ? 'Marked Incomplete' : 'Completed',
 512→    });
 513→  }, [
 514→    selectedEntry,
 515→    showHUD,
 516→  ]);
 517→
 518→  const handleCopy = useCallback(() => {
 519→    if (!selectedEntry) return;
 520→    setActionsOpen(false);
 521→    performCopy(selectedEntry.title, showHUD, {
 522→      hudIcon: <ReminderHUDIcon />,
 523→    });
 524→  }, [
 525→    selectedEntry,
 526→    showHUD,
 527→  ]);
 528→
 529→  const handleCreate = useCallback(() => {
 530→    setActionsOpen(false);
 531→    setEditingReminder(undefined);
 532→    setSubView('create');
 533→  }, []);
 534→
 535→  const handleEdit = useCallback(() => {
 536→    if (!selectedEntry) return;
 537→    setActionsOpen(false);
 538→    setEditingReminder(selectedEntry);
 539→    setSubView('edit');
 540→  }, [selectedEntry]);
 541→
 542→  const handleDelete = useCallback(() => {
 543→    if (!selectedEntry) return;
 544→    const entryId = selectedEntry.id;
 545→    const entryName = selectedEntry.title;
 546→    setActionsOpen(false);
 547→    confirmAlert({
 548→      title: `Delete "${entryName}"?`,
 549→      message: 'This reminder will be permanently deleted.',
 550→      icon: <TrashIcon size={32} />,
 551→      primaryAction: {
 552→        label: 'Delete',
 553→        style: 'destructive',
 554→        onAction: () => {
 555→          setEntries(prev => prev.filter(e => e.id !== entryId));
 556→          reminderDb.delete(entryId).catch(console.error);
 557→          invalidateFts();
 558→          showHUD({
 559→            icon: <ReminderHUDIcon />,
 560→            title: 'Reminder Deleted',
 561→          });
 562→        },
 563→      },
 564→      dismissAction: {
 565→        label: 'Cancel',
 566→        style: 'cancel',
 567→        onAction: () => {},
 568→      },
 569→    });
 570→  }, [
 571→    selectedEntry,
 572→    confirmAlert,
 573→    showHUD,
 574→    invalidateFts,
 575→  ]);
 576→
 577→  const handleFormSubmit = useCallback(
 578→    (form: ReminderFormState) => {
 579→      const dueDate = new Date(form.dueDate + 'T00:00:00');
 580→
 581→      if (subView === 'edit' && editingReminder) {
 582→        const updatedEntry: ReminderEntry = {
 583→          ...editingReminder,
 584→          title: form.title,
 585→          dueDate,
 586→          dueTime: form.dueTime,
 587→          repeat: form.repeat,
 588→          notes: form.notes,
 589→        };
 590→        setEntries(prev =>
 591→          prev.map(e => (e.id === editingReminder.id ? updatedEntry : e)));
 592→        reminderDb
 593→          .update(editingReminder.id, {
 594→            title: form.title,
 595→            due_date: dueDate.toISOString(),
 596→            due_time: form.dueTime,
 597→            repeat: form.repeat,
 598→            notes: form.notes,
