@use '../../styles/tokens';

.reminder-form {
  display: flex;
  flex-direction: column;
  flex: 1;
  padding: tokens.$space-3;
  gap: tokens.$space-3;
  overflow-y: auto;
}

.reminder-check {
  $check-size: 18px;

  display: flex;
  align-items: center;
  justify-content: center;
  width: $check-size;
  height: $check-size;
  flex-shrink: 0;
  border-radius: 50%;
  border: 1.5px solid var(--text-400);
  background: transparent;
  cursor: pointer;
  padding: 0;
  transition:
    background-color tokens.$transition-fast ease,
    border-color tokens.$transition-fast ease;

  &:hover {
    border-color: var(--color-accent);
  }

  &:focus-visible {
    outline: 2px solid var(--color-accent);
    outline-offset: 1px;
  }

  &--completed {
    background: var(--color-accent);
    border-color: var(--color-accent);
  }
}

.reminder-completed-title {
  text-decoration: line-through;
  opacity: 0.6;
}

.reminder-repeat-badge {
  display: inline-flex;
  align-items: center;
  gap: 2px;
  padding: 1px tokens.$space-1;
  border-radius: tokens.$radius-sm;
  background: var(--border-100);
  font-size: tokens.$font-xs;
  color: var(--text-600);
  font-weight: tokens.$font-weight-medium;
}

