struct WindowConfig {
    position_pref: String,
}

impl Default for WindowConfig {
    fn default() -> Self {
        Self {
            position_pref: "top-third".to_string(),
        }
    }
}

#[derive(Default)]
struct AppCache {
    apps: Option<Vec<AppEntry>>,
